private Calendar getCalendar(Date value, TimeZone timeZone) {

    Calendar calendar = null;
    if (timeZone != null) {
        calendar = Calendar.getInstance(timeZone);
    } else {
        calendar = Calendar.getInstance();
    }
    calendar.setTime(value);
    return calendar;
}
